package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Type;

class TypeTokenHashCodeTest {

  @Test
  void testHashCode_returnsPrecomputedHashCode() throws Exception {
    // Use reflection to access private constructor TypeToken(Type)
    Type type = String.class;
    var constructor = TypeToken.class.getDeclaredConstructor(Type.class);
    constructor.setAccessible(true);
    TypeToken<?> typeToken = constructor.newInstance(type);

    // Access private final int hashCode field
    var hashCodeField = TypeToken.class.getDeclaredField("hashCode");
    hashCodeField.setAccessible(true);
    int expectedHashCode = hashCodeField.getInt(typeToken);

    // Call hashCode() method and verify it returns the precomputed hashCode field value
    int actualHashCode = typeToken.hashCode();
    assertEquals(expectedHashCode, actualHashCode);
  }

  @Test
  void testHashCode_consistency() throws Exception {
    Type type = Integer.class;
    var constructor = TypeToken.class.getDeclaredConstructor(Type.class);
    constructor.setAccessible(true);
    TypeToken<?> typeToken = constructor.newInstance(type);

    int firstHashCode = typeToken.hashCode();
    int secondHashCode = typeToken.hashCode();

    // hashCode should be consistent across multiple invocations
    assertEquals(firstHashCode, secondHashCode);
  }
}
